#[test]
fn test_user_creation() {
    let user = User::new("Alice");
    assert_eq!(user.name, "Alice");
    assert_ne!(user.id, 0);
    assert!(user.active, "new users should be active");
    // Custom message with format args:
    assert!(user.age > 0, "expected positive age, got {}", user.age);
}

