struct TestDb {
    pool: PgPool,
    db_name: String,
}

impl TestDb {
    async fn new() -> Self {
        let db_name = format!("test_{}", uuid::Uuid::new_v4());
        // create database, run migrations
        Self { pool, db_name }
    }
}

impl Drop for TestDb {
    fn drop(&mut self) {
        // cleanup: drop test database
    }
}

#[tokio::test]
async fn test_create_user() {
    let db = TestDb::new().await;
    let user = create_user(&db.pool, "Alice").await.unwrap();
    assert_eq!(user.name, "Alice");
    // db automatically cleaned up via Drop
}

#[tokio::test]
async fn test_fetch_user() {
    let pool = setup_test_db().await;
    let user = User::find_by_id(&pool, 1).await.unwrap();
    assert_eq!(user.name, "Alice");
}

// With specific runtime flavor:
#[tokio::test(flavor = "multi_thread", worker_threads = 2)]
async fn test_concurrent_operations() {
    let (a, b) = tokio::join!(
        fetch_data("url1"),
        fetch_data("url2"),
    );
    assert!(a.is_ok());
    assert!(b.is_ok());
}

use proptest::prelude::*;

proptest! {
    #[test]
    fn test_sort_preserves_length(mut v: Vec<i32>) {
        let len = v.len();
        v.sort();
        prop_assert_eq!(v.len(), len);
    }

    #[test]
    fn test_parse_roundtrip(s in "[a-zA-Z0-9]{1,100}") {
        let parsed = MyType::parse(&s);
        if let Ok(val) = parsed {
            prop_assert_eq!(val.to_string(), s);
        }
    }
}

use insta::assert_json_snapshot;

#[test]
fn test_user_serialization() {
    let user = User { id: 1, name: "Alice".into(), active: true };
    assert_json_snapshot!(user, @r###"
    {
      "id": 1,
      "name": "Alice",
      "active": true
    }
    "###);
}

#[test]
fn test_error_display() {
    let err = AppError::NotFound { id: 42 };
    insta::assert_snapshot!(err.to_string(), @"user 42 not found");
}

use mockall::automock;

#[automock]
trait UserRepository {
    fn find_by_id(&self, id: u64) -> Option<User>;
    fn save(&self, user: &User) -> Result<(), String>;
}

#[test]
fn test_user_service() {
    let mut mock = MockUserRepository::new();
    mock.expect_find_by_id()
        .with(mockall::predicate::eq(1))
        .times(1)
        .returning(|_| Some(User { id: 1, name: "Alice".into() }));

    let service = UserService::new(Box::new(mock));
    let user = service.get_user(1).unwrap();
    assert_eq!(user.name, "Alice");
}

use testcontainers::{GenericImage, clients};

#[tokio::test]
async fn test_with_postgres() {
    let docker = clients::Cli::default();
    let pg = docker.run(GenericImage::new("postgres", "16")
        .with_env_var("POSTGRES_PASSWORD", "test")
        .with_exposed_port(5432));

    let port = pg.get_host_port_ipv4(5432);
    let url = format!("postgres://postgres:test@localhost:{port}/postgres");
    let pool = PgPool::connect(&url).await.unwrap();

    sqlx::migrate!().run(&pool).await.unwrap();
    // test against real Postgres
}

