//  --> tests/ui/invalid_derive.rs:4:5

/// Adds two numbers.
///
/// # Examples
///
/// ```
/// use mylib::add;
/// assert_eq!(add(2, 3), 5);
/// ```
///
/// # Errors
///
/// Returns an error if overflow occurs:
///
/// ```
/// use mylib::checked_add;
/// assert!(checked_add(u64::MAX, 1).is_err());
/// ```
pub fn add(a: i32, b: i32) -> i32 { a + b }

# Setup:
# cargo install cargo-fuzz
# cargo fuzz init
# cargo fuzz add parse_input

// fuzz/fuzz_targets/parse_input.rs:
#![no_main]
use libfuzzer_sys::fuzz_target;
use mylib::parse;

fuzz_target!(|data: &[u8]| {
    if let Ok(s) = std::str::from_utf8(data) {
        let _ = parse(s); // must not panic
    }
});

// Run: cargo fuzz run parse_input

// Custom assert helper:
fn assert_json_eq<T: serde::Serialize>(actual: &T, expected_json: &str) {
    let actual_val = serde_json::to_value(actual).unwrap();
    let expected_val: serde_json::Value = serde_json::from_str(expected_json).unwrap();
    assert_eq!(actual_val, expected_val, 
        "\nactual: {}\nexpected: {}",
        serde_json::to_string_pretty(&actual_val).unwrap(),
        expected_json
    );
}

// Or use similar-asserts for better diffs:
use similar_asserts::assert_eq;
assert_eq!(large_struct_a, large_struct_b); // shows colored diff
